logger = logging.getLogger()
logger.setLevel(os.getenv("LOG_LEVEL", "INFO").upper())

s3 = boto3.client("s3")
sns = boto3.client("sns")

OUTPUT_BUCKET = os.getenv("OUTPUT_BUCKET", "")
OUTPUT_PREFIX = os.getenv("OUTPUT_PREFIX", "processed/")
SNS_TOPIC_ARN = os.getenv("SNS_TOPIC_ARN", "")

MAX_BYTES_TO_READ = int(os.getenv("MAX_BYTES_TO_READ", str(25 * 1024 * 1024)))  # 25MB default
COPY_ORIGINAL = os.getenv("COPY_ORIGINAL", "true").lower() in ("1", "true", "yes", "y")


def _json_dumps(obj: Any) -> str:
    return json.dumps(obj, separators=(",", ":"), default=str)


def _now_ms() -> int:
    return int(time.time() * 1000)


def _parse_s3_event_record(record: Dict[str, Any]) -> Tuple[str, str]:
    bucket = record["s3"]["bucket"]["name"]
    key = record["s3"]["object"]["key"]
    key = urllib.parse.unquote_plus(key)
    return bucket, key


def _head_object(bucket: str, key: str) -> Dict[str, Any]:
    return s3.head_object(Bucket=bucket, Key=key)


def _get_object_bytes(bucket: str, key: str, max_bytes: int) -> bytes:
    obj = s3.get_object(Bucket=bucket, Key=key)
    body = obj["Body"].read(max_bytes + 1)
    if len(body) > max_bytes:
        raise ValueError(f"Object too large to read (>{max_bytes} bytes): s3://{bucket}/{key}")
    return body


def _infer_image_type(content_type: Optional[str], key: str, data: bytes) -> str:
    if content_type:
        ct = content_type.lower().strip()
        if ct in ("image/jpeg", "image/jpg"):
            return "jpeg"
        if ct == "image/png":
            return "png"
        if ct == "image/gif":
            return "gif"
        if ct == "image/webp":
            return "webp"
        if ct == "image/bmp":
            return "bmp"
        if ct == "image/tiff":
            return "tiff"
        if ct == "image/heic":
            return "heic"

    lk = key.lower()
    for ext in (".jpg", ".jpeg", ".png", ".gif", ".webp", ".bmp", ".tif", ".tiff", ".heic"):
        if lk.endswith(ext):
            return ext.lstrip(".").replace("jpg", "jpeg")

    if data.startswith(b"\xFF\xD8\xFF"):
        return "jpeg"
    if data.startswith(b"\x89PNG\r\n\x1a\n"):
        return "png"
    if data[:6] in (b"GIF87a", b"GIF89a"):
        return "gif"
    if data.startswith(b"RIFF") and data[8:12] == b"WEBP":
        return "webp"
    if data.startswith(b"BM"):
        return "bmp"
    if data[:4] in (b"II*\x00", b"MM\x00*"):
        return "tiff"

    return "unknown"


def _basic_image_metadata(img_type: str, data: bytes) -> Dict[str, Any]:
    meta: Dict[str, Any] = {
        "type": img_type,
        "bytes": len(data),
        "sha1": None,
        "width": None,
        "height": None,
    }

    try:
        import hashlib

        meta["sha1"] = hashlib.sha1(data).hexdigest()
    except Exception:
        meta["sha1"] = None

    try:
        from PIL import Image  # type: ignore

        from io import BytesIO

        with Image.open(BytesIO(data)) as im:
            meta["width"], meta["height"] = im.size
            meta["mode"] = getattr(im, "mode", None)
            meta["format"] = getattr(im, "format", None)
    except Exception:
        pass

    return meta


def _put_json(bucket: str, key: str, payload: Dict[str, Any], extra_metadata: Optional[Dict[str, str]] = None) -> None:
    md = extra_metadata or {}
    s3.put_object(
        Bucket=bucket,
        Key=key,
        Body=_json_dumps(payload).encode("utf-8"),
        ContentType="application/json",
        Metadata=md,
    )


def _copy_object(src_bucket: str, src_key: str, dst_bucket: str, dst_key: str) -> None:
    s3.copy_object(
        Bucket=dst_bucket,
        Key=dst_key,
        CopySource={"Bucket": src_bucket, "Key": src_key},
        MetadataDirective="COPY",
    )


def _publish_sns(topic_arn: str, subject: str, message: Dict[str, Any]) -> None:
    sns.publish(
        TopicArn=topic_arn,
        Subject=subject[:100],
        Message=_json_dumps(message),
    )


def _output_locations(input_bucket: str, input_key: str, request_id: str) -> Tuple[str, str, str]:
    out_bucket = OUTPUT_BUCKET or input_bucket
    base_name = os.path.basename(input_key.rstrip("/")) or "upload"
    safe_base = base_name.replace(" ", "_")
    prefix = OUTPUT_PREFIX
    if prefix and not prefix.endswith("/"):
        prefix += "/"
    job_prefix = f"{prefix}{request_id}/"
    meta_key = f"{job_prefix}{safe_base}.metadata.json"
    copy_key = f"{job_prefix}{safe_base}"
    return out_bucket, meta_key, copy_key


def process_one_object(bucket: str, key: str, request_id: str) -> Dict[str, Any]:
    start_ms = _now_ms()
    head = _head_object(bucket, key)
    content_type = head.get("ContentType")
    content_length = head.get("ContentLength")

    if content_length is not None and content_length > MAX_BYTES_TO_READ:
        raise ValueError(f"Object too large (ContentLength={content_length}): s3://{bucket}/{key}")

    data = _get_object_bytes(bucket, key, MAX_BYTES_TO_READ)
    img_type = _infer_image_type(content_type, key, data)
    meta = _basic_image_metadata(img_type, data)

    out_bucket, meta_key, copy_key = _output_locations(bucket, key, request_id)

    result = {
        "request_id": request_id,
        "input": {
            "bucket": bucket,
            "key": key,
            "content_type": content_type,
            "content_length": content_length,
            "etag": head.get("ETag"),
            "last_modified": head.get("LastModified"),
        },
        "output": {
            "bucket": out_bucket,
            "metadata_key": meta_key,
            "copied_object_key": copy_key if COPY_ORIGINAL else None,
        },
        "image": meta,
        "timing": {
            "start_ms": start_ms,
            "end_ms": None,
            "duration_ms": None,
        },
    }

    _put_json(out_bucket, meta_key, result, extra_metadata={"source-bucket": bucket, "source-key": key})

    if COPY_ORIGINAL:
        _copy_object(bucket, key, out_bucket, copy_key)

    end_ms = _now_ms()
    result["timing"]["end_ms"] = end_ms
    result["timing"]["duration_ms"] = end_ms - start_ms

    _put_json(out_bucket, meta_key, result, extra_metadata={"source-bucket": bucket, "source-key": key})

    return result


def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    request_id = getattr(context, "aws_request_id", None) or str(uuid.uuid4())
    logger.info(_json_dumps({"msg": "lambda_start", "request_id": request_id, "event": event}))

    records = event.get("Records", [])
    results = []
    errors = []

    for idx, record in enumerate(records):
        try:
            if record.get("eventSource") == "aws:s3" or record.get("EventSource") == "aws:s3":
                bucket, key = _parse_s3_event_record(record)
            else:
                bucket = record.get("bucket") or event.get("bucket")
                key = record.get("key") or event.get("key")
                if not bucket or not key:
                    raise ValueError("Unsupported event format; expected S3 event record or {bucket,key}")

            logger.info(_json_dumps({"msg": "process_object_start", "request_id": request_id, "bucket": bucket, "key": key, "index": idx}))
            res = process_one_object(bucket, key, request_id)
            results.append(res)
            logger.info(_json_dumps({"msg": "process_object_success", "request_id": request_id, "bucket": bucket, "key": key, "index": idx, "output": res.get("output")}))

            if SNS_TOPIC_ARN:
                _publish_sns(
                    SNS_TOPIC_ARN,
                    subject="Image processed",
                    message={
                        "status": "success",
                        "request_id": request_id,
                        "input": {"bucket": bucket, "key": key},
                        "output": res.get("output"),
                        "image": res.get("image"),
                    },
                )

        except Exception as e:
            tb = traceback.format_exc()
            err = {
                "status": "error",
                "request_id": request_id,
                "index": idx,
                "error": str(e),
                "traceback": tb,
                "record": record,
            }
            errors.append(err)
            logger.error(_json_dumps({"msg": "process_object_error", **err}))

            if SNS_TOPIC_ARN:
                try:
                    _publish_sns(
                        SNS_TOPIC_ARN,
                        subject="Image processing failed",
                        message={
                            "status": "error",
                            "request_id": request_id,
                            "error": str(e),
                            "index": idx,
                            "record": record,
                        },
                    )
                except Exception:
                    logger.error(_json_dumps({"msg": "sns_publish_failed", "request_id": request_id, "index": idx, "traceback": traceback.format_exc()}))

    response = {
        "request_id": request_id,
        "processed": len(results),
        "failed": len(errors),
        "results": results,
        "errors": errors,
    }

    logger.info(_json_dumps({"msg": "lambda_end", "request_id": request_id, "summary": {"processed": len(results), "failed": len(errors)}}))

    if errors and not results:
        raise RuntimeError(_json_dumps(response))

    return response